// Worked focus: httpsts-declared-decoded-byte-limits — Enforce declared, compressed, decoded, field-count, nesting, and semantic-size budgets before expensive parsing or effects.
// Evidence: httpsts-worked-http-server-ts-bodies-webhooks-uploads-2
// Competency: httpsts-worked-http-server-ts-bodies-webhooks-uploads-2.
// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_bodies_webhooks_uploads_2(declaredBytes: number, decodedBytes: number, maximumBytes: number, rawPreserved: boolean): { status: number; parse: boolean; reason: string } {
  if (maximumBytes <= 0) return { status: 500, parse: false, reason: "invalid-limit" };
  if (declaredBytes > maximumBytes) {
    return { status: 413, parse: false, reason: "declared-size" };
  }
  if (decodedBytes < 0 || decodedBytes > maximumBytes) {
    return { status: 413, parse: false, reason: "decoded-size" };
  }
  return { status: rawPreserved ? 202 : 400, parse: rawPreserved, reason: "raw-signature" };
}

